<template><article class="card"><h3>Variable Inputs</h3><p v-if="!active.length" class="muted">No variables</p><label v-for="item in active" :key="item.id"><span>{{item.displayName||item.name}} <b v-if="item.required">*</b></span><select v-if="item.type==='select'" :value="String(values[item.name]??'')" @change="set(item.name,($event.target as HTMLSelectElement).value)"><option value="">Select</option><option v-for="option in item.options" :key="option">{{option}}</option></select><input v-else-if="item.type==='boolean'" type="checkbox" :checked="Boolean(values[item.name])" @change="set(item.name,($event.target as HTMLInputElement).checked)"><textarea v-else-if="item.type==='textarea'" :value="String(values[item.name]??'')" @input="set(item.name,($event.target as HTMLTextAreaElement).value)"/><input v-else :type="item.type==='number'?'number':item.type==='date'?'date':'text'" :value="String(values[item.name]??'')" @input="set(item.name,($event.target as HTMLInputElement).value)"><small>{{item.description}}</small><button v-if="item.exampleValue!==undefined" type="button" @click="set(item.name,item.exampleValue)">Apply example</button></label></article></template>
<script setup lang="ts">import{computed}from'vue';import type{PromptOpsPromptVariable}from'@prompt-optimizer/core';const props=defineProps<{variables:PromptOpsPromptVariable[];values:Record<string,unknown>}>();const emit=defineEmits<{change:[Record<string,unknown>]}>();const active=computed(()=>props.variables.filter(x=>!x.unused));const set=(name:string,value:unknown)=>emit('change',{...props.values,[name]:value})</script>
<style scoped>.card{padding:16px;border:1px solid #e5e7eb;border-radius:10px;background:#fff}.card h3{margin-top:0}label{display:grid;gap:5px;margin:12px 0}input,select,textarea{padding:9px;border:1px solid #cbd5e1;border-radius:7px}textarea{min-height:72px}small,.muted{color:#64748b}button{justify-self:start;border:0;background:none;color:#2563eb;cursor:pointer}</style>
